/* Shared elevation structure — all levels inherit these properties.
   Override --_elevation-* custom properties per level to adjust intensity. */
.sm,
.md,
.lg {
  --_elevation-offset-1: var(--imf-ui-border-size-2);
  --_elevation-offset-2: var(--imf-ui-border-size-4);
  --_elevation-opacity-1: 15%;
  --_elevation-opacity-2: 7%;
  --_elevation-border-opacity: 30%;

  background-color: var(--imf-ui-color-bg-main);
  border-radius: var(--explorer-border-radius-default);

  box-shadow:
    0px var(--_elevation-offset-1) 0px 0px
      color-mix(in oklch, var(--imf-ui-color-bg-primary) var(--_elevation-opacity-1), transparent),
    0px var(--_elevation-offset-2) 0px 0px
      color-mix(in oklch, var(--imf-ui-color-bg-primary) var(--_elevation-opacity-2), transparent);

  /* prettier-ignore */
  border: var(--imf-ui-border-size-2) solid
      color-mix(in oklch, var(--imf-ui-color-bg-primary) var(--_elevation-border-opacity), transparent);
}

/* sm — subtle lift; use inside already-elevated containers */
.sm {
  --_elevation-offset-1: 4px;
  --_elevation-offset-2: 8px;
  --_elevation-opacity-1: 12%;
  --_elevation-opacity-2: 6%;
  --_elevation-border-opacity: 25%;
}

/* md — standard lift; panels, sections, cards (default) */
.md {
  --_elevation-offset-1: var(--imf-ui-border-size-4);
  --_elevation-offset-2: var(--imf-ui-border-size-5);
  --_elevation-opacity-1: 20%;
  --_elevation-opacity-2: 10%;
  --_elevation-border-opacity: 50%;
}

/* lg — prominent lift; dropdowns, overlays (TODO: design pending) */
.lg {
  --_elevation-offset-1: 18px;
  --_elevation-offset-2: 30px;
  --_elevation-opacity-1: 28%;
  --_elevation-opacity-2: 14%;
  --_elevation-border-opacity: 65%;
}

import classes from "./elevation.module.css";

// Spread into any component's CVA variants to add elevation.
// sm  — subtle lift; use inside already-elevated containers
// md  — standard lift; panels, sections, cards (default for most components)
// lg  — prominent lift; dropdowns, overlays (design pending)
export const elevationVariants = {
  elevation: {
    sm: classes.sm,
    md: classes.md,
    lg: classes.lg
  }
} as const;

