/* Shared elevation structure — all levels inherit these properties.
   Override --_elevation-* custom properties per level to adjust intensity. */
.sm,
.md,
.lg {
  --_elevation-offset-1: var(--imf-ui-border-size-2);
  --_elevation-offset-2: var(--imf-ui-border-size-4);
  --_elevation-opacity-1: 15%;
  --_elevation-opacity-2: 7%;
  --_elevation-border-opacity: 30%;
  --_elevation-bloom-blur: 12px;
  --_elevation-bloom-spread: 4px;
  --_elevation-bloom-opacity: 10%;
  --_elevation-hard-blur-1: 3px;
  --_elevation-hard-blur-2: 2px;
  --_elevation-spread-1: 2px;
  --_elevation-spread-2: 1px;

  background-color: var(--imf-ui-color-bg-main);
  border-radius: var(--explorer-border-radius-default);

  box-shadow:
    /* Bloom — soft glow radiating outward in all directions */
    0px 0px var(--_elevation-bloom-blur) var(--_elevation-bloom-spread)
      color-mix(in oklch, var(--imf-ui-color-bg-primary) var(--_elevation-bloom-opacity), transparent),
    /* Hard shadow 1 — stepped offset + tiny blur so spread reads as bloom */
    0px var(--_elevation-offset-1) var(--_elevation-hard-blur-1) var(--_elevation-spread-1)
      color-mix(in oklch, var(--imf-ui-color-bg-primary) var(--_elevation-opacity-1), transparent),
    /* Hard shadow 2 */
    0px var(--_elevation-offset-2) var(--_elevation-hard-blur-2) var(--_elevation-spread-2)
      color-mix(in oklch, var(--imf-ui-color-bg-primary) var(--_elevation-opacity-2), transparent);

  /* prettier-ignore */
  border: var(--imf-ui-border-size-2) solid
      color-mix(in oklch, var(--imf-ui-color-bg-primary) var(--_elevation-border-opacity), transparent);
}

/* sm — subtle lift; use inside already-elevated containers */
.sm {
  --_elevation-offset-1: 4px;
  --_elevation-offset-2: 8px;
