  --_elevation-bloom-opacity: 12%;
  --_elevation-hard-blur-1: 3px;
  --_elevation-hard-blur-2: 2px;
  --_elevation-spread-1: 2px;
  --_elevation-spread-2: 1px;
}

/* lg — prominent lift; dropdowns, overlays (TODO: design pending) */
