/* ── Pseudo-element elevation ───────────────────────────────────────────
   ::before and ::after duplicate the element, scale them outward, and
   offset them downward — creating a brutalist stepped bloom with true
   geometric growth. No blur, no box-shadow, just scaled copies.

   Override --_elevation-* custom properties per level to adjust intensity. */

.sm,
.md,
.lg {
  --_elevation-scale-1: 1.02;
  --_elevation-scale-2: 1.05;
  --_elevation-offset-1: 4px;
  --_elevation-offset-2: 10px;
  --_elevation-opacity-1: 0.15;
  --_elevation-opacity-2: 0.07;
  --_elevation-border-opacity: 30%;

  position: relative;
  z-index: 0; /* local stacking context — keeps pseudo-elements behind */

  background-color: var(--imf-ui-color-bg-main);
  border-radius: var(--explorer-border-radius-default);

  /* prettier-ignore */
  border: var(--imf-ui-border-size-2) solid
      color-mix(in oklch, var(--imf-ui-color-bg-primary) var(--_elevation-border-opacity), transparent);
}

/* ── Shared pseudo-element base ─────────────────────────────────────── */

.sm::before,
.md::before,
.lg::before,
.sm::after,
.md::after,
.lg::after {
  content: "";
  position: absolute;
  inset: 0;
  z-index: -1;
  border-radius: inherit;
  background: var(--imf-ui-color-bg-primary);
  pointer-events: none;
}

/* ::before = outer layer (larger scale, more offset, lower opacity) */

.sm::before,
.md::before,
.lg::before {
  opacity: var(--_elevation-opacity-2);
  transform:
    scale(var(--_elevation-scale-2))
    translateY(var(--_elevation-offset-2));
}

/* ::after = inner layer (smaller scale, less offset, higher opacity) */

.sm::after,
.md::after,
.lg::after {
  opacity: var(--_elevation-opacity-1);
  transform:
    scale(var(--_elevation-scale-1))
    translateY(var(--_elevation-offset-1));
}

/* ── sm — subtle lift; use inside already-elevated containers ────────── */

.sm {
  --_elevation-scale-1: 1.01;
  --_elevation-scale-2: 1.025;
  --_elevation-offset-1: 4px;
  --_elevation-offset-2: 8px;
  --_elevation-opacity-1: 0.12;
  --_elevation-opacity-2: 0.06;
  --_elevation-border-opacity: 25%;
}

/* ── md — standard lift; panels, sections, cards (default) ────────────── */

.md {
  --_elevation-scale-1: 1.02;
  --_elevation-scale-2: 1.06;
  --_elevation-offset-1: var(--imf-ui-border-size-4);
  --_elevation-offset-2: var(--imf-ui-border-size-5);
  --_elevation-opacity-1: 0.20;
  --_elevation-opacity-2: 0.10;
  --_elevation-border-opacity: 50%;
}

/* ── lg — prominent lift; dropdowns, overlays (TODO: design pending) ──── */

.lg {
  --_elevation-scale-1: 1.03;
  --_elevation-scale-2: 1.10;
  --_elevation-offset-1: 18px;
  --_elevation-offset-2: 30px;
  --_elevation-opacity-1: 0.28;
  --_elevation-opacity-2: 0.14;
  --_elevation-border-opacity: 65%;
}

